import { useRef, useCallback } from 'react';

function useThrottle<T extends (...args: never[]) => void>(fn: T, wait: number): T {
  const last = useRef(0);
  return useCallback((...args: Parameters<T>) => {
    const now = Date.now();
    if (now - last.current >= wait) {
      last.current = now;
      fn(...args);
    }
  }, [fn, wait]) as T;
}

export { useThrottle };

import { useState, useEffect } from 'react';

function useSessionStorage<T>(key: string, init: T): [T, (v: T) => void] {
  const [value, setValue] = useState<T>(() => {
    try {
      const s = sessionStorage.getItem(key);
      return s ? JSON.parse(s) : init;
    } catch { return init; }
  });

  useEffect(() => {
    try { sessionStorage.setItem(key, JSON.stringify(value)); }
    catch (e) { console.error(e); }
  }, [key, value]);

  return [value, setValue];
}

export { useSessionStorage };

import { useEffect } from 'react';

function useScrollLock(locked: boolean) {
  useEffect(() => {
    if (!locked) return;
    const orig = document.body.style.overflow;
    const scrollY = window.scrollY;
    document.body.style.overflow = 'hidden';
    document.body.style.position = 'fixed';
    document.body.style.top = `-${scrollY}px`;
    document.body.style.width = '100%';
    return () => {
      document.body.style.overflow = orig;
      document.body.style.position = '';
      document.body.style.top = '';
      document.body.style.width = '';
      window.scrollTo(0, scrollY);
    };
  }, [locked]);
}

export { useScrollLock };

import { useState, useEffect, RefObject } from 'react';

function useScrollPosition(ref: RefObject<HTMLElement>) {
  const [pos, setPos] = useState({ top: 0, left: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const handler = () => setPos({ top: el.scrollTop, left: el.scrollLeft });
    el.addEventListener('scroll', handler, { passive: true });
    return () => el.removeEventListener('scroll', handler);
  }, [ref]);

  return pos;
}

export { useScrollPosition };

import { useEffect, useRef, useCallback } from 'react';

function useIsMounted(): () => boolean {
  const mounted = useRef(false);
  useEffect(() => {
    mounted.current = true;
    return () => { mounted.current = false; };
  }, []);
  return useCallback(() => mounted.current, []);
}

