import { useEffect, useRef, DependencyList } from 'react';

function useUpdateEffect(effect: () => void | (() => void), deps: DependencyList) {
  const isFirst = useRef(true);
  useEffect(() => {
    if (isFirst.current) { isFirst.current = false; return; }
    return effect();
  }, deps);
}

