import { useState, useCallback } from 'react';

function useArray<T>(initial: T[] = []) {
  const [arr, setArr] = useState<T[]>(initial);
  const push = useCallback((item: T) => setArr((a) => [...a, item]), []);
  const remove = useCallback((i: number) => setArr((a) => a.filter((_, idx) => idx !== i)), []);
  const update = useCallback((i: number, item: T) => setArr((a) => a.map((v, idx) => idx === i ? item : v)), []);
  const clear = useCallback(() => setArr([]), []);
  return { arr, push, remove, update, clear, setArr };
}

export { useArray };

import { useState, useCallback } from 'react';

function useMap<K, V>(initial: [K, V][] = []) {
  const [map, setMap] = useState<Map<K, V>>(() => new Map(initial));
  const set = useCallback((k: K, v: V) => setMap((m) => new Map(m).set(k, v)), []);
  const del = useCallback((k: K) => setMap((m) => { const n = new Map(m); n.delete(k); return n; }), []);
  const clear = useCallback(() => setMap(new Map()), []);
  const get = useCallback((k: K) => map.get(k), [map]);
  return { map, set, del, clear, get, has: (k: K) => map.has(k) };
}

export { useMap };

import { useState, useCallback } from 'react';

function useSet<T>(initial: T[] = []) {
  const [set, setSet] = useState<Set<T>>(() => new Set(initial));
  const add = useCallback((v: T) => setSet((s) => new Set(s).add(v)), []);
  const del = useCallback((v: T) => setSet((s) => { const n = new Set(s); n.delete(v); return n; }), []);
  const toggle = useCallback((v: T) => setSet((s) => { const n = new Set(s); n.has(v) ? n.delete(v) : n.add(v); return n; }), []);
  const clear = useCallback(() => setSet(new Set()), []);
  return { set, add, del, toggle, clear, has: (v: T) => set.has(v) };
}

export { useSet };

import { useState, useCallback } from 'react';

function useQueue<T>(initial: T[] = []) {
  const [queue, setQueue] = useState<T[]>(initial);
  const enqueue = useCallback((item: T) => setQueue((q) => [...q, item]), []);
  const dequeue = useCallback(() => {
    let removed: T | undefined;
    setQueue((q) => { removed = q[0]; return q.slice(1); });
    return removed;
  }, []);
  const clear = useCallback(() => setQueue([]), []);
  return { queue, enqueue, dequeue, clear, size: queue.length, peek: queue[0] };
}

export { useQueue };

import { useReducer, useCallback } from 'react';

type S<T> = { past: T[]; present: T; future: T[] };
type A<T> = { type: 'SET'; v: T } | { type: 'UNDO' } | { type: 'REDO' };

function reducer<T>(s: S<T>, a: A<T>): S<T> {
  if (a.type === 'SET') return { past: [...s.past, s.present], present: a.v, future: [] };
  if (a.type === 'UNDO' && s.past.length)
    return { past: s.past.slice(0, -1), present: s.past[s.past.length-1], future: [s.present, ...s.future] };
  if (a.type === 'REDO' && s.future.length)
    return { past: [...s.past, s.present], present: s.future[0], future: s.future.slice(1) };
  return s;
}

function useStateWithHistory<T>(init: T) {
  const [s, dispatch] = useReducer(reducer<T>, { past: [], present: init, future: [] });
  const set = useCallback((v: T) => dispatch({ type: 'SET', v }), []);
  const undo = useCallback(() => dispatch({ type: 'UNDO' }), []);
  const redo = useCallback(() => dispatch({ type: 'REDO' }), []);
  return { value: s.present, set, undo, redo, canUndo: s.past.length > 0, canRedo: s.future.length > 0 };
}

export { useStateWithHistory };

import { useState, useEffect, useRef } from 'react';

function useIdle(timeout = 30000): boolean {
  const [idle, setIdle] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout>>();

  useEffect(() => {
    const reset = () => {
      setIdle(false);
      clearTimeout(timer.current);
      timer.current = setTimeout(() => setIdle(true), timeout);
    };
    const events = ['mousemove', 'keydown', 'click', 'scroll'];
    events.forEach((e) => window.addEventListener(e, reset));
    reset();
    return () => {
      events.forEach((e) => window.removeEventListener(e, reset));
      clearTimeout(timer.current);
    };
  }, [timeout]);

  return idle;
}

export { useIdle };

import { useState, useEffect } from 'react';

interface NetworkState { online: boolean; effectiveType?: string; downlink?: number; }

function useNetworkState(): NetworkState {
  const getState = (): NetworkState => ({
    online: navigator.onLine,
    effectiveType: (navigator as any).connection?.effectiveType,
    downlink: (navigator as any).connection?.downlink,
  });
  const [state, setState] = useState<NetworkState>(getState);

  useEffect(() => {
    const update = () => setState(getState());
    window.addEventListener('online', update);
    window.addEventListener('offline', update);
    return () => {
      window.removeEventListener('online', update);
      window.removeEventListener('offline', update);
    };
  }, []);

  return state;
}

export { useNetworkState };

