import { useCallback, useRef } from 'react';

function useLongPress(callback: () => void, delay = 500) {
  const timer = useRef<ReturnType<typeof setTimeout>>();

  const start = useCallback(() => {
    timer.current = setTimeout(callback, delay);
  }, [callback, delay]);

  const stop = useCallback(() => {
    clearTimeout(timer.current);
  }, []);

  return {
    onMouseDown: start, onMouseUp: stop, onMouseLeave: stop,
    onTouchStart: start, onTouchEnd: stop,
  };
}

export { useLongPress };

import { useRef, useCallback } from 'react';

type Dir = 'left' | 'right' | 'up' | 'down' | null;

function useSwipe(onSwipe: (dir: Dir) => void, minDist = 50) {
  const start = useRef<{ x: number; y: number } | null>(null);

  const onTouchStart = useCallback((e: React.TouchEvent) => {
    const t = e.touches[0];
    start.current = { x: t.clientX, y: t.clientY };
  }, []);

  const onTouchEnd = useCallback((e: React.TouchEvent) => {
    if (!start.current) return;
    const t = e.changedTouches[0];
    const dx = t.clientX - start.current.x;
    const dy = t.clientY - start.current.y;
    start.current = null;
    if (Math.abs(dx) < minDist && Math.abs(dy) < minDist) return;
    if (Math.abs(dx) > Math.abs(dy)) onSwipe(dx > 0 ? 'right' : 'left');
    else onSwipe(dy > 0 ? 'down' : 'up');
  }, [onSwipe, minDist]);

  return { onTouchStart, onTouchEnd };
}

export { useSwipe };

import { useState, useEffect, useRef } from 'react';

function useElementSize<T extends HTMLElement>() {
  const ref = useRef<T>(null);
  const [size, setSize] = useState({ width: 0, height: 0 });

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new ResizeObserver(([entry]) => {
      const { width, height } = entry.contentRect;
      setSize({ width, height });
    });
    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return { ref, ...size };
}

export { useElementSize };

import { useEffect, useRef, useState, useCallback, RefObject } from 'react';

function useResizeObserver<T extends HTMLElement>(ref: RefObject<T>, callback: (entry: ResizeObserverEntry) => void) {
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new ResizeObserver(([entry]) => callback(entry));
    obs.observe(el);
    return () => obs.disconnect();
  }, [ref, callback]);
}

function Box() {
  const ref = useRef<HTMLDivElement>(null);
  const [w, setW] = useState(0);
  const cb = useCallback((e: ResizeObserverEntry) => setW(Math.round(e.contentRect.width)), []);
  useResizeObserver(ref, cb);
  return <div ref={ref} style={{ resize: 'horizontal', overflow: 'auto', minWidth: 100 }}>너비: {w}px</div>;
}

export { useResizeObserver };

import { useState, useEffect } from 'react';

type Status = 'idle' | 'loading' | 'ready' | 'error';

function useScript(src: string): Status {
  const [status, setStatus] = useState<Status>(src ? 'loading' : 'idle');

  useEffect(() => {
    if (!src) return;
    let el = document.querySelector<HTMLScriptElement>(`script[src="${src}"]`);
    if (!el) {
      el = document.createElement('script');
      el.src = src; el.async = true;
      document.body.appendChild(el);
    }
    const onLoad = () => setStatus('ready');
    const onError = () => setStatus('error');
    el.addEventListener('load', onLoad);
    el.addEventListener('error', onError);
    return () => { el?.removeEventListener('load', onLoad); el?.removeEventListener('error', onError); };
  }, [src]);

  return status;
}

export { useScript };

