import { useState, useEffect } from 'react';

function useDarkMode(): [boolean, () => void] {
  const [dark, setDark] = useState(() => {
    const stored = localStorage.getItem('darkMode');
    if (stored !== null) return stored === 'true';
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', dark);
    localStorage.setItem('darkMode', String(dark));
  }, [dark]);

  return [dark, () => setDark((d) => !d)];
}

export { useDarkMode };

import { useState, useRef, useCallback } from 'react';

function useStopwatch() {
  const [elapsed, setElapsed] = useState(0);
  const [running, setRunning] = useState(false);
  const startRef = useRef(0);
  const id = useRef<ReturnType<typeof setInterval>>();

  const run = useCallback(() => {
    startRef.current = Date.now() - elapsed;
    id.current = setInterval(() => setElapsed(Date.now() - startRef.current), 10);
    setRunning(true);
  }, [elapsed]);

  const stop = useCallback(() => { clearInterval(id.current); setRunning(false); }, []);
  const reset = useCallback(() => { clearInterval(id.current); setElapsed(0); setRunning(false); }, []);

  const ms = elapsed % 1000;
  const s = Math.floor(elapsed / 1000) % 60;
  const m = Math.floor(elapsed / 60000);
  return { running, elapsed, m, s, ms, run, stop, reset };
}

export { useStopwatch };

import { useEffect, useRef, RefObject } from 'react';

function useClickAway<T extends HTMLElement>(callback: (e: Event) => void): RefObject<T> {
  const ref = useRef<T>(null);

  useEffect(() => {
    const handler = (e: Event) => {
      if (ref.current && !ref.current.contains(e.target as Node)) {
        callback(e);
      }
    };
    document.addEventListener('pointerdown', handler);
    return () => document.removeEventListener('pointerdown', handler);
  }, [callback]);

  return ref;
}

export { useClickAway };

import { useEffect, useRef } from 'react';

function useWhyDidYouUpdate(name: string, props: Record<string, unknown>) {
  const prev = useRef<Record<string, unknown>>({});

  useEffect(() => {
    const changed: Record<string, { from: unknown; to: unknown }> = {};
    const all = new Set([...Object.keys(prev.current), ...Object.keys(props)]);
    all.forEach((k) => {
      if (!Object.is(prev.current[k], props[k])) changed[k] = { from: prev.current[k], to: props[k] };
    });
    if (Object.keys(changed).length) {
      console.group(`[useWhyDidYouUpdate] ${name}`);
      console.table(changed);
      console.groupEnd();
    }
    prev.current = props;
  });
}

export { useWhyDidYouUpdate };

