import React, { useState, useRef, useEffect } from 'react';

function Popover({ trigger, content }: { trigger: React.ReactNode; content: React.ReactNode }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const h = (e: MouseEvent) => { if (!ref.current?.contains(e.target as Node)) setOpen(false); };
    document.addEventListener('mousedown', h);
    return () => document.removeEventListener('mousedown', h);
  }, []);

  return (
    <div ref={ref} style={{ position: 'relative', display: 'inline-block' }}>
      <span onClick={() => setOpen((o) => !o)}>{trigger}</span>
      {open && (
        <div style={{ position: 'absolute', top: '110%', left: 0, zIndex: 200,
          background: '#fff', border: '1px solid #e5e7eb', borderRadius: 6,
          boxShadow: '0 4px 12px rgba(0,0,0,0.1)', padding: 12, minWidth: 160 }}>
          {content}
        </div>
      )}
    </div>
  );
}

export default Popover;

import React, { useState, useEffect } from 'react';

type Item = { label: string; onClick: () => void };

function ContextMenu({ items, children }: { items: Item[]; children: React.ReactNode }) {
  const [pos, setPos] = useState<{ x: number; y: number } | null>(null);

  useEffect(() => {
    const close = () => setPos(null);
    window.addEventListener('click', close);
    return () => window.removeEventListener('click', close);
  }, []);

  return (
    <div onContextMenu={(e) => { e.preventDefault(); setPos({ x: e.clientX, y: e.clientY }); }}>
      {children}
      {pos && (
        <ul style={{ position: 'fixed', top: pos.y, left: pos.x, zIndex: 999,
          background: '#fff', border: '1px solid #ddd', borderRadius: 6,
          boxShadow: '0 2px 8px rgba(0,0,0,0.12)', listStyle: 'none', padding: 4, margin: 0 }}>
          {items.map((it, i) => (
            <li key={i} onClick={it.onClick} style={{ padding: '6px 16px', cursor: 'pointer' }}>{it.label}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default ContextMenu;

import React from 'react';

interface SliderProps {
  value: number; onChange: (v: number) => void;
  min?: number; max?: number; step?: number; label?: string;
}

function Slider({ value, onChange, min = 0, max = 100, step = 1, label }: SliderProps) {
  const pct = ((value - min) / (max - min)) * 100;
  return (
    <div>
      {label && <label style={{ display: 'block', marginBottom: 4 }}>{label}: {value}</label>}
      <div style={{ position: 'relative', height: 20, display: 'flex', alignItems: 'center' }}>
        <div style={{ width: '100%', height: 4, background: '#e5e7eb', borderRadius: 2 }}>
          <div style={{ width: `${pct}%`, height: '100%', background: '#1976d2', borderRadius: 2 }} />
        </div>
        <input type="range" min={min} max={max} step={step} value={value}
          onChange={(e) => onChange(+e.target.value)} aria-label={label}
          style={{ position: 'absolute', width: '100%', opacity: 0, cursor: 'pointer', height: 20 }} />
      </div>
    </div>
  );
}

export default Slider;

import React from 'react';

interface RangeSliderProps {
  low: number; high: number; min?: number; max?: number;
  onChange: (low: number, high: number) => void;
}

function RangeSlider({ low, high, min = 0, max = 100, onChange }: RangeSliderProps) {
  const pL = ((low - min) / (max - min)) * 100;
  const pH = ((high - min) / (max - min)) * 100;
  return (
    <div style={{ position: 'relative', height: 24, display: 'flex', alignItems: 'center' }}>
      <div style={{ width: '100%', height: 4, background: '#e5e7eb', borderRadius: 2, position: 'relative' }}>
        <div style={{ position: 'absolute', left: `${pL}%`, width: `${pH - pL}%`, height: '100%', background: '#1976d2' }} />
      </div>
      {(['low', 'high'] as const).map((t) => (
        <input key={t} type="range" min={min} max={max}
          value={t === 'low' ? low : high}
          onChange={(e) => t === 'low' ? onChange(Math.min(+e.target.value, high), high) : onChange(low, Math.max(+e.target.value, low))}
          style={{ position: 'absolute', width: '100%', opacity: 0, cursor: 'pointer' }} />
      ))}
    </div>
  );
}

export default RangeSlider;

