import React, { useState } from 'react';

function Calendar({ selected, onSelect }: { selected?: string; onSelect: (d: string) => void }) {
  const today = new Date();
  const [year, setYear] = useState(today.getFullYear());
  const [month, setMonth] = useState(today.getMonth());
  const days = new Date(year, month + 1, 0).getDate();
  const first = new Date(year, month, 1).getDay();
  const cells = Array.from({ length: first + days }, (_, i) => (i < first ? null : i - first + 1));
  const fmt = (d: number) => `${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
  const prev = () => month === 0 ? (setYear((y)=>y-1), setMonth(11)) : setMonth((m)=>m-1);
  const next = () => month === 11 ? (setYear((y)=>y+1), setMonth(0)) : setMonth((m)=>m+1);
  return (
    <div style={{ display: 'inline-block' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8 }}>
        <button onClick={prev}>◀</button>
        <strong>{year}년 {month+1}월</strong>
        <button onClick={next}>▶</button>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7,32px)', gap: 2, textAlign: 'center' }}>
        {'일월화수목금토'.split('').map((d)=><div key={d} style={{fontSize:11,color:'#6b7280'}}>{d}</div>)}
        {cells.map((d,i)=>(
          <div key={i} onClick={()=>d&&onSelect(fmt(d))}
            style={{ lineHeight:'32px', cursor: d?'pointer':'default', borderRadius:'50%',
              background: d&&fmt(d)===selected?'#1976d2':'transparent',
              color: d&&fmt(d)===selected?'#fff':d?'#111':'transparent' }}>{d??''}</div>
        ))}
      </div>
    </div>
  );
}

export default Calendar;

