import React, { useState, KeyboardEvent } from 'react';

function ChipInput({ value, onChange }: { value: string[]; onChange: (v: string[]) => void }) {
  const [input, setInput] = useState('');
  const add = () => { const t = input.trim(); if (t && !value.includes(t)) onChange([...value, t]); setInput(''); };
  const onKey = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') { e.preventDefault(); add(); }
    if (e.key === 'Backspace' && !input && value.length) onChange(value.slice(0, -1));
  };
  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, padding: 6, border: '1px solid #d1d5db', borderRadius: 6 }}>
      {value.map((tag) => (
        <span key={tag} style={{ display: 'inline-flex', alignItems: 'center', gap: 4, padding: '2px 8px',
          background: '#dbeafe', color: '#1d4ed8', borderRadius: 9999, fontSize: 13 }}>
          {tag}
          <button onClick={() => onChange(value.filter((t) => t !== tag))}
            style={{ background: 'none', border: 'none', cursor: 'pointer', padding: 0, color: '#1d4ed8' }}>×</button>
        </span>
      ))}
      <input value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={onKey}
        placeholder="태그 입력 후 Enter"
        style={{ border: 'none', outline: 'none', minWidth: 120, fontSize: 13 }} />
    </div>
  );
}

