import React, { useRef, useState } from 'react';

function OTPInput({ length = 6, onComplete }: { length?: number; onComplete: (code: string) => void }) {
  const [values, setValues] = useState<string[]>(Array(length).fill(''));
  const refs = useRef<(HTMLInputElement | null)[]>([]);

  const handle = (i: number, v: string) => {
    if (!/^[0-9]?$/.test(v)) return;
    const next = [...values]; next[i] = v; setValues(next);
    if (v && i < length - 1) refs.current[i+1]?.focus();
    if (next.every(Boolean)) onComplete(next.join(''));
  };

  const onKey = (i: number, e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Backspace' && !values[i] && i > 0) refs.current[i-1]?.focus();
  };

  return (
    <div style={{ display: 'flex', gap: 8 }}>
      {values.map((v, i) => (
        <input key={i} ref={(el) => { refs.current[i] = el; }}
          value={v} maxLength={1} inputMode="numeric"
          onChange={(e) => handle(i, e.target.value)}
          onKeyDown={(e) => onKey(i, e)}
          style={{ width: 40, height: 48, textAlign: 'center', fontSize: 20, fontWeight: 700,
            border: '1px solid #d1d5db', borderRadius: 6 }} />
      ))}
    </div>
  );
}

export default OTPInput;

import React from 'react';

function getStrength(pw: string): number {
  let s = 0;
  if (pw.length >= 8) s++;
  if (/[A-Z]/.test(pw)) s++;
  if (/[0-9]/.test(pw)) s++;
  if (/[^A-Za-z0-9]/.test(pw)) s++;
  return s;
}

const LABELS = ['약함', '보통', '강함', '매우 강함'];
const COLORS = ['#ef4444', '#f97316', '#eab308', '#22c55e'];

function PasswordStrengthMeter({ password }: { password: string }) {
  const strength = password ? getStrength(password) : 0;
  return (
    <div>
      <div style={{ display: 'flex', gap: 4, marginTop: 6 }}>
        {Array.from({ length: 4 }, (_, i) => (
          <div key={i} style={{ flex: 1, height: 4, borderRadius: 2,
            background: i < strength ? COLORS[strength-1] : '#e5e7eb', transition: 'background 0.2s' }} />
        ))}
      </div>
      {password && <p style={{ fontSize: 12, color: COLORS[strength-1], marginTop: 4 }}>{LABELS[strength-1]}</p>}
    </div>
  );
}

export default PasswordStrengthMeter;

