import React from 'react';

interface Option { value: string; label: string; }

function CheckboxGroup({ options, selected, onChange }: { options: Option[]; selected: string[]; onChange: (v: string[]) => void }) {
  const allChecked = options.every((o) => selected.includes(o.value));
  const toggleAll = () => onChange(allChecked ? [] : options.map((o) => o.value));
  const toggle = (v: string) => onChange(selected.includes(v) ? selected.filter((s) => s !== v) : [...selected, v]);

  return (
    <div>
      <label style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8, fontWeight: 600 }}>
        <input type="checkbox" checked={allChecked} onChange={toggleAll} /> 전체 선택
      </label>
      {options.map((opt) => (
        <label key={opt.value} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 6, paddingLeft: 8 }}>
          <input type="checkbox" checked={selected.includes(opt.value)} onChange={() => toggle(opt.value)} />
          {opt.label}
        </label>
      ))}
    </div>
  );
}

export default CheckboxGroup;

import React from 'react';

interface NumberInputProps { value: number; onChange: (v: number) => void; min?: number; max?: number; step?: number; }

function NumberInput({ value, onChange, min = -Infinity, max = Infinity, step = 1 }: NumberInputProps) {
  const clamp = (v: number) => Math.min(Math.max(v, min), max);
  return (
    <div style={{ display: 'inline-flex', alignItems: 'center', border: '1px solid #d1d5db', borderRadius: 6, overflow: 'hidden' }}>
      <button onClick={() => onChange(clamp(value - step))} disabled={value <= min}
        style={{ padding: '6px 12px', border: 'none', background: '#f9fafb', cursor: 'pointer', fontSize: 16 }}>-</button>
      <input type="number" value={value} onChange={(e) => onChange(clamp(Number(e.target.value)))}
        style={{ width: 60, textAlign: 'center', border: 'none', outline: 'none', padding: '6px 0', fontSize: 14 }} />
      <button onClick={() => onChange(clamp(value + step))} disabled={value >= max}
        style={{ padding: '6px 12px', border: 'none', background: '#f9fafb', cursor: 'pointer', fontSize: 16 }}>+</button>
    </div>
  );
}

export default NumberInput;

