import { useState, useCallback } from 'react';

interface BooleanHelpers { value: boolean; setTrue: () => void; setFalse: () => void; toggle: () => void; set: (v: boolean) => void; }

function useBoolean(init = false): BooleanHelpers {
  const [value, setValue] = useState(init);
  const setTrue = useCallback(() => setValue(true), []);
  const setFalse = useCallback(() => setValue(false), []);
  const toggle = useCallback(() => setValue((v) => !v), []);
  return { value, setTrue, setFalse, toggle, set: setValue };
}

export { useBoolean };

import { useEffect, useRef, MutableRefObject } from 'react';

function useMountedRef(): MutableRefObject<boolean> {
  const mounted = useRef(false);
  useEffect(() => {
    mounted.current = true;
    return () => { mounted.current = false; };
  }, []);
  return mounted;
}

