export { useMountedRef };

import React, { useState, useEffect } from 'react';

function ScrollToTop({ threshold = 200 }: { threshold?: number }) {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const handler = () => setVisible(window.scrollY > threshold);
    window.addEventListener('scroll', handler, { passive: true });
    return () => window.removeEventListener('scroll', handler);
  }, [threshold]);

  if (!visible) return null;
  return (
    <button onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
      style={{ position: 'fixed', bottom: 24, right: 24, zIndex: 100,
        width: 44, height: 44, borderRadius: '50%',
        background: '#1976d2', color: '#fff', border: 'none',
        fontSize: 20, cursor: 'pointer', boxShadow: '0 2px 8px rgba(0,0,0,0.2)' }}
      aria-label="맨 위로">↑</button>
  );
}

export default ScrollToTop;

import React, { useState, useEffect } from 'react';

function ReadingProgress({ color = '#1976d2', height = 3 }: { color?: string; height?: number }) {
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const update = () => {
      const el = document.documentElement;
      const total = el.scrollHeight - el.clientHeight;
      setProgress(total > 0 ? (el.scrollTop / total) * 100 : 0);
    };
    window.addEventListener('scroll', update, { passive: true });
    return () => window.removeEventListener('scroll', update);
  }, []);

  return (
    <div style={{ position: 'fixed', top: 0, left: 0, zIndex: 9999, width: '100%', height }}>
      <div style={{ width: `${progress}%`, height: '100%', background: color, transition: 'width 0.05s' }} />
    </div>
  );
}

export default ReadingProgress;

import { useState, useEffect, useRef } from 'react';

function useFetchAbort<T>(url: string) {
  const [data, setData] = useState<T | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const ctrl = useRef<AbortController | null>(null);

  useEffect(() => {
    ctrl.current = new AbortController();
    setLoading(true); setError(null);
    fetch(url, { signal: ctrl.current.signal })
      .then((r) => r.json())
      .then((d) => { setData(d); setLoading(false); })
      .catch((e) => { if (e.name !== 'AbortError') { setError(e.message); setLoading(false); } });
    return () => ctrl.current?.abort();
  }, [url]);

  return { data, error, loading, abort: () => ctrl.current?.abort() };
}

export { useFetchAbort };

import React, { useState, useRef, useLayoutEffect } from 'react';

function Collapsible({ title, children, defaultOpen = false }: { title: React.ReactNode; children: React.ReactNode; defaultOpen?: boolean }) {
