  const [height, setHeight] = useState<number | undefined>(defaultOpen ? undefined : 0);
  const ref = useRef<HTMLDivElement>(null);

  useLayoutEffect(() => {
    if (!ref.current) return;
    setHeight(open ? ref.current.scrollHeight : 0);
  }, [open]);

  return (
    <div style={{ border: '1px solid #e5e7eb', borderRadius: 6, overflow: 'hidden' }}>
      <button onClick={() => setOpen((o) => !o)}
        style={{ width: '100%', display: 'flex', justifyContent: 'space-between',
          padding: '10px 14px', background: 'none', border: 'none', cursor: 'pointer', fontWeight: 600 }}>
        {title}
        <span style={{ transition: 'transform 0.2s', transform: open ? 'rotate(180deg)' : 'rotate(0)' }}>▾</span>
      </button>
      <div ref={ref} style={{ height, overflow: 'hidden', transition: 'height 0.25s ease' }}>
        <div style={{ padding: '8px 14px 12px' }}>{children}</div>
      </div>
    </div>
  );
}

export default Collapsible;

import { useState, useCallback, RefObject } from 'react';

function useFullscreen(ref: RefObject<HTMLElement>) {
  const [isFullscreen, setIsFullscreen] = useState(false);

  const enter = useCallback(async () => {
    try { await ref.current?.requestFullscreen(); setIsFullscreen(true); }
    catch (e) { console.error(e); }
  }, [ref]);

  const exit = useCallback(async () => {
    await document.exitFullscreen();
    setIsFullscreen(false);
  }, []);

  const toggle = useCallback(() => (isFullscreen ? exit() : enter()), [isFullscreen, enter, exit]);

  return { isFullscreen, enter, exit, toggle };
}

export { useFullscreen };

import { useState, useEffect } from 'react';

function useWindowFocus(): boolean {
  const [focused, setFocused] = useState(() => document.hasFocus());

  useEffect(() => {
    const onFocus = () => setFocused(true);
    const onBlur = () => setFocused(false);
    window.addEventListener('focus', onFocus);
    window.addEventListener('blur', onBlur);
    return () => {
      window.removeEventListener('focus', onFocus);
      window.removeEventListener('blur', onBlur);
    };
  }, []);

  return focused;
}

function FocusAwareTitle() {
  const focused = useWindowFocus();
  return <p>탭 상태: {focused ? '활성' : '비활성'}</p>;
}

export { useWindowFocus };

