import React, { useRef, useState } from 'react';

interface MenuItem { label: string; onClick: () => void; }

function Menu({ trigger, items }: { trigger: React.ReactNode; items: MenuItem[] }) {
  const [open, setOpen] = useState(false);
  const [active, setActive] = useState(-1);
  const close = () => { setOpen(false); setActive(-1); };
  const onKey = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') { close(); return; }
    if (e.key === 'ArrowDown') setActive((a) => Math.min(a+1, items.length-1));
    if (e.key === 'ArrowUp') setActive((a) => Math.max(a-1, 0));
    if (e.key === 'Enter' && active >= 0) { items[active].onClick(); close(); }
  };
  return (
    <div style={{ position: 'relative', display: 'inline-block' }} onKeyDown={onKey} tabIndex={0}>
      <div onClick={() => setOpen((o) => !o)}>{trigger}</div>
      {open && (
        <ul role="menu" style={{ position: 'absolute', top: '110%', left: 0, background: '#fff',
          border: '1px solid #e5e7eb', borderRadius: 6, listStyle: 'none', padding: 4, margin: 0, zIndex: 50, minWidth: 160 }}>
          {items.map((it, i) => (
            <li key={i} role="menuitem" onClick={() => { it.onClick(); close(); }}
              style={{ padding: '7px 14px', cursor: 'pointer', background: i===active ? '#f3f4f6' : 'transparent', borderRadius: 4 }}>{it.label}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Menu;

