import { useReducer, useEffect } from 'react';

function useLocalToggle(key: string, defaultOn = false): [boolean, () => void] {
  const init = (): boolean => {
    const stored = localStorage.getItem(key);
    return stored !== null ? stored === 'true' : defaultOn;
  };
  const [on, dispatch] = useReducer((state: boolean) => !state, false, init);

  useEffect(() => {
    localStorage.setItem(key, String(on));
  }, [key, on]);

  return [on, dispatch];
}

function SidebarToggle() {
  const [open, toggle] = useLocalToggle('sidebar-open', true);
  return <button onClick={toggle}>{open ? '사이드바 닫기' : '사이드바 열기'}</button>;
}

export { useLocalToggle };

import { useState, useEffect, useRef, useCallback } from 'react';

function useCountdown(start: number) {
  const [count, setCount] = useState(start);
  const [running, setRunning] = useState(false);
  const id = useRef<ReturnType<typeof setInterval>>();

  useEffect(() => {
    if (!running) return;
    id.current = setInterval(() => {
      setCount((c) => {
        if (c <= 1) { clearInterval(id.current); setRunning(false); return 0; }
        return c - 1;
      });
    }, 1000);
    return () => clearInterval(id.current);
  }, [running]);

  const play = useCallback(() => { if (count > 0) setRunning(true); }, [count]);
  const stop = useCallback(() => { clearInterval(id.current); setRunning(false); }, []);
  const reset = useCallback(() => { clearInterval(id.current); setRunning(false); setCount(start); }, [start]);

  return { count, running, play, stop, reset };
}

export { useCountdown };

import { useState, useRef, useCallback } from 'react';

function useMediaRecorder() {
  const [recording, setRecording] = useState(false);
  const [url, setUrl] = useState<string | null>(null);
  const recorder = useRef<MediaRecorder | null>(null);
  const chunks = useRef<Blob[]>([]);

  const start = useCallback(async () => {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    const mr = new MediaRecorder(stream);
    chunks.current = [];
    mr.ondataavailable = (e) => chunks.current.push(e.data);
    mr.onstop = () => { setUrl(URL.createObjectURL(new Blob(chunks.current, { type: 'audio/webm' }))); };
    mr.start(); recorder.current = mr; setRecording(true);
  }, []);

  const stop = useCallback(() => { recorder.current?.stop(); setRecording(false); }, []);

  return { recording, url, start, stop };
}

export { useMediaRecorder };

