import { useState, useCallback } from 'react';

type ClipStatus = 'idle' | 'success' | 'error';

function useClipboardWrite(resetDelay = 3000) {
  const [status, setStatus] = useState<ClipStatus>('idle');

  const write = useCallback(async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setStatus('success');
    } catch {
      setStatus('error');
    } finally {
      setTimeout(() => setStatus('idle'), resetDelay);
    }
  }, [resetDelay]);

  return { write, status, isSuccess: status === 'success', isError: status === 'error' };
}

export { useClipboardWrite };

