import { useState, useCallback, useEffect } from 'react';

function useFavorites(key = 'favorites') {
  const [favorites, setFavorites] = useState<string[]>(() => {
    try { return JSON.parse(localStorage.getItem(key) ?? '[]'); }
    catch { return []; }
  });

  useEffect(() => {
    localStorage.setItem(key, JSON.stringify(favorites));
  }, [key, favorites]);

  const add = useCallback((id: string) => setFavorites((f) => f.includes(id) ? f : [...f, id]), []);
  const remove = useCallback((id: string) => setFavorites((f) => f.filter((v) => v !== id)), []);
  const toggle = useCallback((id: string) => setFavorites((f) => f.includes(id) ? f.filter((v) => v !== id) : [...f, id]), []);
  const has = useCallback((id: string) => favorites.includes(id), [favorites]);

  return { favorites, add, remove, toggle, has };
}

export { useFavorites };

import { useState, useEffect, useRef, RefObject } from 'react';

function useInView<T extends HTMLElement>(options?: IntersectionObserverInit): [RefObject<T>, boolean] {
  const ref = useRef<T>(null);
  const [inView, setInView] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(([entry]) => setInView(entry.isIntersecting), options);
    obs.observe(el);
    return () => obs.disconnect();
  }, [options?.threshold, options?.root, options?.rootMargin]);

  return [ref, inView];
}

function FadeIn({ children }: { children: React.ReactNode }) {
  const [ref, inView] = useInView<HTMLDivElement>({ threshold: 0.2 });
  return (
    <div ref={ref} style={{ opacity: inView ? 1 : 0, transition: 'opacity 0.5s', padding: 16 }}>
      {children}
    </div>
  );
}

export { useInView };

import { useState, useCallback } from 'react';

function useFormSubmit<T>(onSubmit: (data: T) => Promise<void>) {
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState(false);

  const handleSubmit = useCallback(async (data: T) => {
    setSubmitting(true);
    setError(null);
    setSuccess(false);
    try {
      await onSubmit(data);
      setSuccess(true);
    } catch (e) {
      setError(e instanceof Error ? e.message : '오류가 발생했습니다');
    } finally {
      setSubmitting(false);
    }
  }, [onSubmit]);

  return { handleSubmit, submitting, error, success };
}

export { useFormSubmit };

