import { useState, useEffect, useRef } from 'react';

function useSpring(target: number, stiffness = 0.1, damping = 0.8): number {
  const [value, setValue] = useState(target);
  const vel = useRef(0);
  const cur = useRef(target);
  const raf = useRef<number>();

  useEffect(() => {
    const animate = () => {
      const force = (target - cur.current) * stiffness;
      vel.current = (vel.current + force) * damping;
      cur.current += vel.current;
      setValue(cur.current);
      if (Math.abs(vel.current) > 0.001 || Math.abs(target - cur.current) > 0.001) {
        raf.current = requestAnimationFrame(animate);
      }
    };
    raf.current = requestAnimationFrame(animate);
    return () => { if (raf.current) cancelAnimationFrame(raf.current); };
  }, [target, stiffness, damping]);

  return value;
}

export { useSpring };

import React, { useState, useEffect } from 'react';

function CountdownBadge({ seconds, onExpire, label }: { seconds: number; onExpire: () => void; label?: string }) {
  const [left, setLeft] = useState(seconds);

  useEffect(() => {
    if (left <= 0) { onExpire(); return; }
    const id = setTimeout(() => setLeft((n) => n - 1), 1000);
    return () => clearTimeout(id);
  }, [left, onExpire]);

  const pct = (left / seconds) * 100;
  const color = left <= 5 ? '#ef4444' : left <= 15 ? '#f97316' : '#1976d2';

  return (
    <div style={{ display: 'inline-flex', flexDirection: 'column', alignItems: 'center', gap: 4 }}>
      {label && <span style={{ fontSize: 12, color: '#6b7280' }}>{label}</span>}
      <div style={{ position: 'relative', width: 52, height: 52 }}>
        <svg viewBox="0 0 36 36" width={52} height={52}>
          <circle cx="18" cy="18" r="15" fill="none" stroke="#e5e7eb" strokeWidth="3" />
          <circle cx="18" cy="18" r="15" fill="none" stroke={color} strokeWidth="3"
            strokeDasharray={`${pct * 0.942} 94.2`} strokeLinecap="round" transform="rotate(-90 18 18)" />
        </svg>
        <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, fontSize: 14, color }}>{left}</div>
      </div>
    </div>
  );
}

export default CountdownBadge;

import React, { useState, useRef } from 'react';

interface Option { value: string; label: string; }

function Listbox({ options, value, onChange }: { options: Option[]; value: string; onChange: (v: string) => void }) {
  const [focused, setFocused] = useState(-1);
  const ref = useRef<HTMLUListElement>(null);

  const onKey = (e: React.KeyboardEvent) => {
    const idx = options.findIndex((o) => o.value === value);
    if (e.key === 'ArrowDown') { const n = Math.min(idx+1, options.length-1); onChange(options[n].value); setFocused(n); }
    if (e.key === 'ArrowUp') { const n = Math.max(idx-1, 0); onChange(options[n].value); setFocused(n); }
  };

  return (
    <ul ref={ref} role="listbox" aria-activedescendant={value} tabIndex={0} onKeyDown={onKey}
      style={{ listStyle: 'none', padding: 4, margin: 0, border: '1px solid #d1d5db', borderRadius: 6, outline: 'none', maxHeight: 200, overflowY: 'auto' }}>
      {options.map((opt, i) => (
        <li key={opt.value} role="option" aria-selected={opt.value === value}
          id={opt.value} onClick={() => { onChange(opt.value); setFocused(i); }}
          style={{ padding: '7px 12px', borderRadius: 4, cursor: 'pointer',
            background: opt.value === value ? '#dbeafe' : i === focused ? '#f3f4f6' : 'transparent',
            fontWeight: opt.value === value ? 600 : 400 }}>
          {opt.label}
        </li>
      ))}
    </ul>
  );
}

export default Listbox;

import { useState, useEffect } from 'react';

interface Position { x: number; y: number; }

function useMousePosition(relative?: HTMLElement | null): Position {
  const [pos, setPos] = useState<Position>({ x: 0, y: 0 });

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (relative) {
        const rect = relative.getBoundingClientRect();
        setPos({ x: e.clientX - rect.left, y: e.clientY - rect.top });
      } else {
        setPos({ x: e.clientX, y: e.clientY });
      }
    };
    window.addEventListener('mousemove', handler);
    return () => window.removeEventListener('mousemove', handler);
  }, [relative]);

  return pos;
}

function CursorDot() {
  const { x, y } = useMousePosition();
  return (
    <div style={{ position: 'fixed', left: x, top: y, width: 8, height: 8,
      borderRadius: '50%', background: '#1976d2', pointerEvents: 'none', transform: 'translate(-50%,-50%)' }} />
  );
}

export { useMousePosition };
